]
const TC001_BASE_URL = `/nodes/${TC001_NODE.id}/projects/${TC001_PROJECT_ID}`

async function mockProjectOverview(page: Page) {
  await page.route('/graphql', async (route) => {
    const body = route.request().postDataJSON() as { query: string }
